// Pipeline file for Jenkins Deployment pipeline with SCM (Source Code Management).  
pipeline {   
     agent any // Use 'any' to allow all agents in the workspace that have access permissions – it is a good practice. If you want only specific nodes, use their names or labels here as an array of strings like ['node1', 'node2']. This will ensure your pipeline runs on these particular machines if they are available and reachable from Jenkins server itself
     parameters { // Parameters for the Pipeline to accept inputs – we'll need URLs in this case.  
         string(name: 'URL_S3', description: '', defaultValue: "")   
         string(name: 'BUILDID', description: '', defaultValue: "", parameters:[choice(choices:'Build ID from previous build or new one? ', name: 'PUSHED')])   // This parameter will be used to identify whether it's a push (new) version of the app, if not provided then use latest available.
     } 
    stages {     
         stage('Checkout Codebase from SCM'){// Check out code source and get build number/id at same time using Jenkins Pipeline   // This is where you check-in your project to a version control system like Git or Subversion, then use the 'Build Number' (if any) as part of our job name.
             steps { 
                 script{    
                     git url: "https://github/com/userName", branch: '', poll: false    // Fetching source code from Github repository  
                      withCredentials([[$class: 'UsernamePasswordMultiBinding', credentialsID: 'git-creds']]) {  /* This is where you provide your username and password to access the private repo */     }     
                 script()         }} // End of Checkout Codebase from SCM stage  
             }//End check out code base steps   
        },      
          .                  .....and so on for other stages as per requirement.  This will ensure that all necessary components are available in the Jenkins environment and can be accessed by our pipeline script, ie., build number/id is passed to it from previous job or new one if no input provided then latest version of app should always run